export type Task<T> = (data: T) => Promise<void>;

export class TaskQueue<T> extends EventTarget {
  private pendingTasks: Array<{ data: T; attempt: number }> = [];
  private runningCount = 0;
  private isShutdown = false;
  private readonly concurrency: number;
  private readonly baseDelay: number;
  private readonly timeout?: number;

  constructor(options: TaskQueueOptions<T>) {
    super();
    this.concurrency = options.concurrency;
    this.baseDelay = options.baseDelay;
    this.timeout = options.timeout;
  }

  enqueue(task: Task<T>, data: T): void {
    if (this.isShutdown) throw new Error('Queue is shutdown');

    // Sort by priority (lower number = higher priority) using binary search for O(log n)
    const index = this.pendingTasks.findIndex(t => t.data.priority < data.priority);
    const taskEntry: { data: T; attempt: number } = { data, attempt: 0 };

    if (index === -1) {
      this.pendingTasks.push(taskEntry);
    } else {
      this.pendingTasks.splice(index, 0, taskEntry);
    }

    // Fire retrying event immediately if we hit concurrency limit
    if (this.runningCount >= this.concurrency) {
      this.dispatchEvent(new CustomEvent('retrying', { detail: { data } }));
    }
  }

  private async processQueue(): Promise<void> {
    while (this.pendingTasks.length > 0 && this.runningCount < this.concurrency && !this.isShutdown) {
      const taskEntry = this.pendingTasks.shift()!;
      this.runningCount++;

      try {
        await this.executeWithRetry(taskEntry);
        this.dispatchEvent(new CustomEvent('completed', { detail: { data: taskEntry.data } }));
      } catch (error) {
        if (!this.isShutdown) {
          this.dispatchEvent(new CustomEvent('failed', { detail: { data: taskEntry.data, error } }));
        }
      } finally {
        this.runningCount--;
      }
    }

    if (this.pendingTasks.length === 0 && this.runningCount === 0) {
      this.dispatchEvent(new CustomEvent('drained'));
    }
  }

  private async executeWithRetry(taskEntry: { data: T; attempt: number }): Promise<void> {
    const { data, attempt } = taskEntry;

    // Race between task execution and timeout
    let result: void | Error;
    try {
      const taskFn = data.task;
      result = await Promise.race([
        taskFn(data),
        this.timeout ? new Promise<never>((_, reject) => 
          setTimeout(() => reject(new Error('timeout')), this.timeout)
        ) : Promise.reject(new Error('no timeout'))
      ]);
    } catch (error) {
      result = error as Error;
    }

    if (result instanceof Error) {
      const nextAttempt = attempt + 1;
      const delay = this.baseDelay * Math.pow(2, nextAttempt - 1) + Math.random() * 100;

      await new Promise<void>(resolve => setTimeout(resolve, delay));

      if (this.isShutdown) throw result;

      taskEntry.attempt = nextAttempt;
      this.dispatchEvent(new CustomEvent('retrying', { detail: { data, attempt: nextAttempt } }));
    }
  }

  shutdown(): Promise<void> {
    this.isShutdown = true;

    // Reject all pending enqueues
    if (this.pendingTasks.length > 0) {
      throw new Error('Queue is shutdown');
    }

    // Wait for all running tasks to finish
    return new Promise<void>(resolve => {
      const checkInterval = setInterval(() => {
        if (this.runningCount === 0) {
          clearInterval(checkInterval);
          resolve();
        }
      }, 10);
    });
  }

  private get priority(): number {
    return this.pendingTasks.length > 0 ? this.pendingTasks[0].data.priority : Infinity;
  }
}
