export class TaskQueue<T> implements EventTarget {
  private options: TaskQueueOptions;
  private pendingTasks: Task<T>[] = [];
  private runningCount = 0;
  private isShutdown = false;
  private readonly events: Map<string, Set<EventListener>> = new Map();

  constructor(options: TaskQueueOptions) {
    this.options = options;
    this.addEventListener('completed', () => {});
    this.addEventListener('failed', () => {});
    this.addEventListener('retrying', () => {});
    this.addEventListener('drained', () => {});
  }

  async enqueue(task: Task<T>): Promise<void> {
    if (this.isShutdown) throw new Error('Queue is shutdown');
    const insertPos = this.pendingTasks.findIndex(t => t.priority > task.priority);
    this.pendingTasks.splice(insertPos === -1 ? this.pendingTasks.length : insertPos, 0, task);
    await this.processQueue();
  }

  private async processQueue(): Promise<void> {
    while (this.runningCount < this.options.concurrency && this.pendingTasks.length > 0) {
      const task = this.pendingTasks.shift()!;
      this.runningCount++;
      try {
        await this.executeWithRetry(task);
        this.dispatchEvent('completed', { taskId: task.id });
      } catch (err) {
        if (!this.isShutdown) {
          if (task.attempts && task.attempts >= 3) throw err;
          const delay = this.options.baseDelay * Math.pow(2, task.attempts || 0) + Math.random() * 100;
          await new Promise(r => setTimeout(r, delay));
          task.attempts = (task.attempts || 0) + 1;
          this.dispatchEvent('retrying', { taskId: task.id, attempts: task.attempts });
        } else {
          throw err;
        }
      } finally {
        this.runningCount--;
      }
    }
    if (this.pendingTasks.length === 0 && this.runningCount === 0) {
      this.dispatchEvent('drained', {});
    }
  }

  private async executeWithRetry(task: Task<T>): Promise<T> {
    const result = await Promise.race([
      task.fn(),
      new Promise<never>((_, reject) => setTimeout(() => reject(new Error('timeout')), this.options.timeout))
    ]);
    return result;
  }

  shutdown(): Promise<void> {
    this.isShutdown = true;
    const promises: Promise<void>[] = [];
    while (this.pendingTasks.length > 0) {
      const task = this.pendingTasks.shift()!;
      promises.push(this.executeWithRetry(task).catch(() => {}));
    }
    return Promise.all(promises);
  }

  addEventListener<K extends keyof EventMap>(name: K, listener: (this: EventMap[K], event: EventMap[K]) => void): void {
    if (!this.events.has(name)) this.events.set(name, new Set());
    this.events.get(name)!.add(listener);
  }

  private dispatchEvent<K extends keyof EventMap>(name: K, event: EventMap[K]): void {
    const listeners = this.events.get(name);
    if (listeners) listeners.forEach(fn => fn.call(this, event));
  }
}

