type StateConfig<S extends string = string> = { entry?: (ctx: any) => void; exit?: (ctx: any) => void };
type Transition = { target: string; guard?: (ctx: any) => boolean; action?: (ctx: any) => any } | string;
type MachineConfig<S, E, C> = Record<S, { on: Partial<Record<E, Transition>> }> & { initial: S };
export class StateMachine<S extends string, E extends string, C = any> {
  private states: Map<string, StateConfig> = new Map();
  private config: MachineConfig<S, E, C>;
  private current: string | null = null;
  private context: C;
  private listeners: Set<(state: S) => void> = new Set();

  constructor(config: MachineConfig<S, E, C>, ctx?: C) {
    this.config = config;
    this.context = ctx || {} as C;
    if (config.initial) this.current = config.initial;
    Object.entries(config).forEach(([state, cfg]) => this.states.set(state, cfg));
  }

  private notifyListeners() {
    this.listeners.forEach(cb => cb(this.current!));
  }

  private applyStateTransition(old: string | null, newTarget: string) {
    if (old && this.states.get(old)?.exit) this.states.get(old)!.exit(this.context);
    if (this.states.get(newTarget)?.entry) this.states.get(newTarget)!.entry(this.context);
    this.current = newTarget;
    this.notifyListeners();
  }

  send(event: E): void {
    const stateConfig = this.states.get(this.current!);
    if (!stateConfig || !stateConfig.on[event]) return;
    const trans = stateConfig.on[event];
    if (typeof trans === 'string') {
      this.applyStateTransition(this.current, trans);
      return;
    }
    if (trans.guard && !trans.guard(this.context)) return;
    if (trans.action) this.context = { ...this.context, ...trans.action(this.context) };
    this.applyStateTransition(this.current, trans.target);
  }

  onChange(cb: (state: S) => void): () => void {
    this.listeners.add(cb);
    return () => this.listeners.delete(cb);
  }

  toJSON(): { state: string; context: C } {
    return { state: this.current, context: this.context };
  }

  static fromJSON<S extends string, E extends string, C>(config: MachineConfig<S, E, C>, data: { state: S; context: C }): StateMachine<S, E, C> {
    const machine = new StateMachine(config);
    machine.current = data.state;
    machine.context = data.context;
    return machine;
  }
}
